import { html, customElement } from '@umbraco-cms/backoffice/external/lit';
import { UmbModalBaseElement } from '@umbraco-cms/backoffice/modal';
import { UMB_ACTION_EVENT_CONTEXT } from '@umbraco-cms/backoffice/action';
import type { EntrySearchResultMetadata, FormDesign } from '@umbraco-forms/generated';
import { UmbRequestReloadChildrenOfEntityEvent } from '@umbraco-cms/backoffice/entity-action';
import { FORMS_FORM_FOLDER_ENTITY_TYPE, FORMS_FORM_ROOT_ENTITY_TYPE } from '../../../entities.js';
import { FormsFormDetailRepository } from '../../../repository/index.js';
import type { FormsFormDeleteConfirmModalData } from './index.js';

@customElement('forms-form-delete-confirm-modal')
export class FormsFormDeleteConfirmModalElement extends UmbModalBaseElement<FormsFormDeleteConfirmModalData> {

	#formToDelete?: FormDesign | null;
	#formRecordsMetadata?: EntrySearchResultMetadata | null;
	#formHasRelations?: boolean | null;

	#formDetailRepository = new FormsFormDetailRepository(this);

	async connectedCallback() {
		super.connectedCallback();

		if (!this.data?.unique) return;

		const formToDeleteResponse = await this.#formDetailRepository.requestByUnique(this.data.unique);
		this.#formToDelete = formToDeleteResponse.data;

		const formRecordsMetadataResponse = await this.#formDetailRepository.requestRecordsMetaData(this.data.unique);
		this.#formRecordsMetadata = formRecordsMetadataResponse.data;

		const formHasRelationsResponse = await this.#formDetailRepository.requestHasRelations(this.data.unique);
		this.#formHasRelations = formHasRelationsResponse.data;

		this.requestUpdate();
	}

	async #deleteForm(event: PointerEvent) {
		event.stopPropagation();

		if (this.data?.unique) {
			const { data } = await this.#formDetailRepository.requestByUnique(this.data.unique);
			if (!data) throw new Error('Item not found.');

			await this.#formDetailRepository.delete(this.data.unique);

			const eventContext = await this.getContext(UMB_ACTION_EVENT_CONTEXT);
			const eventArgs = {
				entityType: data.parentUnique ? FORMS_FORM_FOLDER_ENTITY_TYPE : FORMS_FORM_ROOT_ENTITY_TYPE,
				unique: data.parentUnique || null,
			};
			const reloadEvent = new UmbRequestReloadChildrenOfEntityEvent(eventArgs);
			eventContext.dispatchEvent(reloadEvent);
		}
		this._submitModal();
	}

	render() {
		return html`
			<umb-body-layout headline=${this.localize.term('formDelete_modalHeadline')}>
				<uui-box>
					<p>${this.localize.term('formDelete_title', this.#formToDelete?.name)}</p>
					<p><i>${this.localize.term('formDelete_timingNote')}</i></p>
					<p>${this.localize.term('formDelete_recordDeleteNote')}</p>
					<p>${(this.#formRecordsMetadata?.count == 0
						? html`${this.localize.term('formDelete_noRecordDetail')}`
						: html`${this.localize.term('formDelete_recordDetail', this.#formRecordsMetadata?.count, this.#formRecordsMetadata?.lastSubmittedDate)}`)}</p>
					<p>${(this.#formHasRelations
						? html`${this.localize.term('formDelete_deleteWarning')}`
						: html`${this.localize.term('formDelete_noReferencedMessage')}`)}</p>
				</uui-box>
				<uui-button slot="actions" id="cancel" label=${this.localize.term('general_cancel')} @click="${this._rejectModal}">${this.localize.term('general_cancel')}</uui-button>
				<uui-button slot="actions" type="button" label=${this.localize.term('general_delete')} look="primary" color="danger" @click=${this.#deleteForm}></uui-button>
			</umb-body-layout>
		`;
	}
}

export default FormsFormDeleteConfirmModalElement;

declare global {
	interface HTMLElementTagNameMap {
		'forms-form-delete-confirm-modal': FormsFormDeleteConfirmModalElement;
	}
}
